2113→const VirtualHostImpl* RouteMatcher::findVirtualHost(const Http::RequestHeaderMap& headers) const {
  2114→  // Fast path the case where we only have a default virtual host.
  2115→  if (virtual_hosts_.empty() && wildcard_virtual_host_suffixes_.empty() &&
  2116→      wildcard_virtual_host_prefixes_.empty()) {
  2117→    return default_virtual_host_.get();
  2118→  }
  2119→
  2120→  // There may be no authority in early reply paths in the HTTP connection manager.
  2121→  if (headers.Host() == nullptr) {
  2122→    return nullptr;
  2123→  }
  2124→
  2125→  // If 'ignore_port_in_host_matching' is set, ignore the port number in the host header(if any).
  2126→  absl::string_view host_header_value = headers.getHostValue();
  2127→  if (ignorePortInHostMatching()) {
  2128→    if (const absl::string_view::size_type port_start =
  2129→            Http::HeaderUtility::getPortStart(host_header_value);
  2130→        port_start != absl::string_view::npos) {
  2131→      host_header_value = host_header_value.substr(0, port_start);
  2132→    }
  2133→  }
  2134→  // TODO (@rshriram) Match Origin header in WebSocket
  2135→  // request with VHost, using wildcard match
  2136→  // Lower-case the value of the host header, as hostnames are case insensitive.
  2137→  const std::string host = absl::AsciiStrToLower(host_header_value);
  2138→  const auto iter = virtual_hosts_.find(host);
  2139→  if (iter != virtual_hosts_.end()) {
  2140→    return iter->second.get();
